import React, { useState, useEffect } from 'react';
import './index.css';
import Sidebar from './components/Sidebar';
import ChatWindow from './components/ChatWindow';
import ProfileModal from './components/ProfileModal';
import SettingsPanel from './components/SettingsPanel';
import LoginModal from './components/LoginModal';
import axios from 'axios';
import { themes } from './themeConfig';

const API = axios.create({ baseURL: 'http://localhost:8000' });

function App() {
  const [loggedIn, setLoggedIn] = useState(false);
  const [username, setUsername] = useState('游客');
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [homeworkCheckMode, setHomeworkCheckMode] = useState(false);

  const theme = themes.rose;   // 固定黑白主题

  const [mobileDrawerOpen, setMobileDrawerOpen] = useState(false);
  const [showProfile, setShowProfile] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showLogin, setShowLogin] = useState(false);

  // 加载聊天历史
  useEffect(() => {
    if (loggedIn) {
      API.get(`/api/history?username=${username}`)
        .then(res => {
          const msgs = res.data.history.map(h => ({ sender: h.role, text: h.content }));
          setMessages(msgs);
        })
        .catch(() => { });
    }
  }, [loggedIn, username]);

  // 发送消息（含批改模式拦截）
  const sendMessage = async () => {
    if (!input.trim()) return;

    // 批改模式
    if (homeworkCheckMode) {
      setHomeworkCheckMode(false);
      const userMsg = { sender: 'user', text: `📝 批改作业：\n${input}` };
      setMessages(prev => [...prev, userMsg]);
      setInput('');

      const loadingMsg = { sender: 'assistant', text: 'loading' };
      setMessages(prev => [...prev, loadingMsg]);

      try {
        const res = await API.post('/api/homework-check', { content: input });
        setMessages(prev => [...prev.slice(0, -1), { sender: 'assistant', text: res.data.reply }]);
      } catch {
        setMessages(prev => [...prev.slice(0, -1), { sender: 'assistant', text: '❌ 批改服务暂不可用' }]);
      }
      return;
    }

    // 正常对话
    const userMsg = { sender: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');

    const loadingMsg = { sender: 'assistant', text: 'loading' };
    setMessages(prev => [...prev, loadingMsg]);

    try {
      const res = await API.post('/api/chat', {
        message: input,
        username,
        logged_in: loggedIn
      });
      const data = res.data;
      const aiMsg = {
        sender: 'assistant',
        text: data.reply,
        download: data.worksheet_ready ? { title: data.title } : null
      };
      setMessages(prev => [...prev.slice(0, -1), aiMsg]);
    } catch (err) {
      setMessages(prev => [
        ...prev.slice(0, -1),
        { sender: 'assistant', text: '❌ 小智老师走神了，请稍后再试~' }
      ]);
    }
  };

  // 清空对话
  const clearHistory = async () => {
    if (loggedIn) {
      try { await API.post(`/api/clear-history?username=${username}`); } catch { }
    }
    setMessages([]);
    setHomeworkCheckMode(false);
  };

  // 获取错题本
  const fetchMistakes = async () => {
    try {
      const res = await API.get('/api/mistakes');
      setMessages(prev => [...prev, { sender: 'assistant', text: res.data.mistakes }]);
    } catch {
      setMessages(prev => [...prev, { sender: 'assistant', text: '❌ 加载错题本失败' }]);
    }
  };

  // 获取学习周报
  const fetchReport = async () => {
    try {
      const res = await API.get('/api/report');
      setMessages(prev => [...prev, { sender: 'assistant', text: res.data.report }]);
    } catch {
      setMessages(prev => [...prev, { sender: 'assistant', text: '❌ 生成周报失败' }]);
    }
  };

  // 下载作业（修正为动态创建 a 标签触发下载）
  const downloadWorksheet = (answers) => {
    const url = `http://localhost:8000/api/download-worksheet?answers=${answers}`;
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', '');
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // 登录/退出
  const handleLoginSuccess = (user) => {
    setLoggedIn(true);
    setUsername(user);
    setShowLogin(false);
    setMessages([]);
  };

  const handleLogout = () => {
    setLoggedIn(false);
    setUsername('游客');
    setShowSettings(false);
    setShowProfile(false);
    setMessages([]);
    setHomeworkCheckMode(false);
  };

  return (
    <div className="h-screen flex transition-all duration-700 bg-white">
      {/* 桌面端侧边栏 */}
      <div className="hidden md:block">
        <Sidebar
          loggedIn={loggedIn}
          username={username}
          sidebarOpen={sidebarOpen}
          setSidebarOpen={setSidebarOpen}
          theme={theme}
          onAvatarClick={() => loggedIn ? setShowProfile(true) : setShowLogin(true)}
          onFetchMistakes={fetchMistakes}
          onFetchReport={fetchReport}
          onStartHomeworkCheck={() => setHomeworkCheckMode(true)}
          onClearHistory={clearHistory}
          isMobile={false}
          onCloseMobile={() => { }}
        />
      </div>

      {/* 移动端侧边栏抽屉 */}
      {mobileDrawerOpen && (
        <div className="fixed inset-0 z-50 md:hidden">
          <div
            className="absolute inset-0 bg-black/40 backdrop-blur-sm"
            onClick={() => setMobileDrawerOpen(false)}
          />
          <div className="absolute left-0 top-0 h-full w-72 animate-slideInLeft">
            <Sidebar
              loggedIn={loggedIn}
              username={username}
              sidebarOpen={true}
              setSidebarOpen={() => setMobileDrawerOpen(false)}
              theme={theme}
              onAvatarClick={() => loggedIn ? setShowProfile(true) : setShowLogin(true)}
              onFetchMistakes={fetchMistakes}
              onFetchReport={fetchReport}
              onStartHomeworkCheck={() => setHomeworkCheckMode(true)}
              onClearHistory={clearHistory}
              isMobile={true}
              onCloseMobile={() => setMobileDrawerOpen(false)}
            />
          </div>
        </div>
      )}

      {/* 聊天区 */}
      <ChatWindow
        messages={messages}
        input={input}
        setInput={setInput}
        onSend={sendMessage}
        theme={theme}
        sidebarOpen={sidebarOpen}
        onOpenMobileSidebar={() => setMobileDrawerOpen(true)}
        onDownload={downloadWorksheet}
      />

      {/* 弹窗 */}
      {showProfile && (
        <ProfileModal
          username={username}
          theme={theme}
          onClose={() => setShowProfile(false)}
          onOpenSettings={() => { setShowProfile(false); setShowSettings(true); }}
        />
      )}
      {showSettings && (
        <SettingsPanel
          theme={theme}
          onClose={() => setShowSettings(false)}
          onLogout={handleLogout}
          onSwitchAccount={() => {
            setShowSettings(false);
            setShowLogin(true);
            handleLogout();
          }}
        />
      )}
      {showLogin && (
        <LoginModal
          theme={theme}
          onClose={() => setShowLogin(false)}
          onLoginSuccess={handleLoginSuccess}
        />
      )}
    </div>
  );
}

export default App;
